dashboard.definition:
{
  "title": "Source - Apache Access",
  "description": "Apache combined access logs — customer experience, error detection, and traffic analysis",
  "dataSources": {
    "ds_total_events": {
      "type": "ds.search",
      "name": "Total Requests Over Time",
      "options": {
        "query": "| tstats count where index=fake_tshrt sourcetype=\"FAKE:access_combined\" by _time span=1h"
      }
    },
    "ds_error_rate": {
      "type": "ds.search",
      "name": "Error Rate (4xx+5xx)",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" | eval error=if(status>=400,1,0) | stats sum(error) as errors, count as total | eval pct=round(errors/total*100,1) | eval count=pct.\"%\" | table count"
      }
    },
    "ds_unique_visitors": {
      "type": "ds.search",
      "name": "Unique Visitors",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" clientip=* | stats dc(clientip) as count"
      }
    },
    "ds_pages_served": {
      "type": "ds.search",
      "name": "Pages Served (2xx)",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" status>=200 status<300 | stats count"
      }
    },
    "ds_requests_by_status": {
      "type": "ds.search",
      "name": "Requests Over Time by Status Category",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" | eval status_cat=case(status<300,\"2xx Success\",status<400,\"3xx Redirect\",status<500,\"4xx Client Error\",status>=500,\"5xx Server Error\") | timechart span=1h count by status_cat"
      }
    },
    "ds_top_pages": {
      "type": "ds.search",
      "name": "Top Pages by Request Count",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" uri=* | stats count by uri | sort -count | head 15 | rename uri as \"Page\""
      }
    },
    "ds_method_distribution": {
      "type": "ds.search",
      "name": "HTTP Method Distribution",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" | stats count by method | sort -count"
      }
    },
    "ds_top_client_ips": {
      "type": "ds.search",
      "name": "Top Client IPs",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" clientip=* | stats count by clientip | sort -count | head 15 | rename clientip as \"Client IP\""
      }
    },
    "ds_recent_errors": {
      "type": "ds.search",
      "name": "Recent Errors",
      "options": {
        "query": "index=fake_tshrt sourcetype=\"FAKE:access_combined\" status>=400 | table _time clientip method uri status bytes | sort -_time | head 30 | rename clientip as \"Client IP\" method as \"Method\" uri as \"URI\" status as \"Status\" bytes as \"Bytes\""
      }
    }
  },
  "visualizations": {
    "viz_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "# Source — Apache Access\n\n**Sourcetype:** `FAKE:access_combined` | **Coverage:** WEB-01, WEB-02 (Boston DMZ) | **Format:** Apache Combined Log\n\n**Why monitor?** Monitor customer experience — detect errors, track traffic patterns, identify performance issues before they impact revenue.",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_kpi_total_requests": {
      "type": "splunk.singlevalue",
      "title": "Total Requests",
      "dataSources": { "primary": "ds_total_events" },
      "options": {
        "majorValue": "> sparklineValues | lastPoint()",
        "sparklineValues": "> primary | seriesByName('count')",
        "sparklineDisplay": "below",
        "majorColor": "#00D2FF",
        "backgroundColor": "transparent",
        "showSparklineAreaGraph": true,
        "sparklineStrokeColor": "#00D2FF"
      }
    },
    "viz_kpi_error_rate": {
      "type": "splunk.singlevalue",
      "title": "Error Rate",
      "dataSources": { "primary": "ds_error_rate" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#DC4E41",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_unique_visitors": {
      "type": "splunk.singlevalue",
      "title": "Unique Visitors",
      "dataSources": { "primary": "ds_unique_visitors" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#7B56DB",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_kpi_pages_served": {
      "type": "splunk.singlevalue",
      "title": "Pages Served",
      "dataSources": { "primary": "ds_pages_served" },
      "options": {
        "majorValue": "> primary | seriesByName('count') | lastPoint()",
        "majorColor": "#53A051",
        "backgroundColor": "transparent",
        "sparklineDisplay": "off"
      }
    },
    "viz_requests_by_status": {
      "type": "splunk.area",
      "title": "Requests Over Time by Status Category",
      "dataSources": { "primary": "ds_requests_by_status" },
      "options": {
        "stackMode": "stacked",
        "legendDisplay": "right",
        "nullValueDisplay": "zero",
        "areaOpacity": 0.7,
        "backgroundColor": "transparent",
        "xAxisTitleVisibility": "hide",
        "yAxisTitleText": "Requests / hour",
        "yAxisTitleVisibility": "show",
        "yAxisAbbreviation": "auto",
        "seriesColorsByField": {
          "2xx Success": "#53A051",
          "3xx Redirect": "#00D2FF",
          "4xx Client Error": "#F8BE34",
          "5xx Server Error": "#DC4E41"
        }
      },
      "showProgressBar": true,
      "showLastUpdated": true
    },
    "viz_top_pages": {
      "type": "splunk.bar",
      "title": "Top Pages by Request Count",
      "dataSources": { "primary": "ds_top_pages" },
      "options": {
        "seriesColors": ["#00D2FF"],
        "legendDisplay": "off",
        "xAxisTitleText": "Requests",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_method_distribution": {
      "type": "splunk.pie",
      "title": "HTTP Method Distribution",
      "dataSources": { "primary": "ds_method_distribution" },
      "options": {
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true,
        "seriesColorsByField": {
          "GET": "#00D2FF",
          "POST": "#53A051",
          "PUT": "#7B56DB",
          "DELETE": "#DC4E41",
          "HEAD": "#F8BE34",
          "OPTIONS": "#009CEB"
        }
      }
    },
    "viz_top_client_ips": {
      "type": "splunk.bar",
      "title": "Top Client IPs — Detect Bots or Heavy Users",
      "dataSources": { "primary": "ds_top_client_ips" },
      "options": {
        "seriesColors": ["#7B56DB"],
        "legendDisplay": "off",
        "xAxisTitleText": "Requests",
        "xAxisTitleVisibility": "show",
        "yAxisTitleVisibility": "hide",
        "backgroundColor": "transparent"
      },
      "showProgressBar": true
    },
    "viz_errors_header": {
      "type": "splunk.markdown",
      "options": {
        "markdown": "### Recent Errors (4xx + 5xx)",
        "fontColor": "#C3CBD4"
      }
    },
    "viz_recent_errors": {
      "type": "splunk.table",
      "title": "Recent Errors",
      "dataSources": { "primary": "ds_recent_errors" },
      "options": {
        "count": 20,
        "showRowNumbers": false
      },
      "showProgressBar": true,
      "showLastUpdated": true
    }
  },
  "inputs": {
    "input_global_trp": {
      "type": "input.timerange",
      "title": "Time Range",
      "options": {
        "token": "global_time",
        "defaultValue": "1767225600,1769904000"
      }
    }
  },
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "$global_time.earliest$",
            "latest": "$global_time.latest$"
          }
        }
      }
    }
  },
  "layout": {
    "type": "grid",
    "globalInputs": ["input_global_trp"],
    "structure": [
      { "item": "viz_header", "type": "block", "position": { "x": 0, "y": 0, "w": 1200, "h": 130 } },
      { "item": "viz_kpi_total_requests", "type": "block", "position": { "x": 0, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_error_rate", "type": "block", "position": { "x": 300, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_unique_visitors", "type": "block", "position": { "x": 600, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_kpi_pages_served", "type": "block", "position": { "x": 900, "y": 130, "w": 300, "h": 120 } },
      { "item": "viz_requests_by_status", "type": "block", "position": { "x": 0, "y": 250, "w": 1200, "h": 350 } },
      { "item": "viz_top_pages", "type": "block", "position": { "x": 0, "y": 600, "w": 600, "h": 300 } },
      { "item": "viz_method_distribution", "type": "block", "position": { "x": 600, "y": 600, "w": 600, "h": 300 } },
      { "item": "viz_top_client_ips", "type": "block", "position": { "x": 0, "y": 900, "w": 1200, "h": 300 } },
      { "item": "viz_errors_header", "type": "block", "position": { "x": 0, "y": 1200, "w": 1200, "h": 50 } },
      { "item": "viz_recent_errors", "type": "block", "position": { "x": 0, "y": 1250, "w": 1200, "h": 400 } }
    ]
  }
}
